-- ************************************** ANALYTICS.MV_PATIENT_RISK_SUMMARY
CREATE MATERIALIZED VIEW ANALYTICS.MV_PATIENT_RISK_SUMMARY
(
  CREATED_TIMESTAMP,
  CREATED_BY_NAME,
  UPDATED_TIMESTAMP,
  UPDATED_BY_NAME
)
AS
SELECT 
    p.PATIENT_KEY,
    p.PATIENT_ID,
    p.FIRST_NAME,
    p.LAST_NAME,
    p.DATE_OF_BIRTH,
    p.GENDER,
    pr.RISK_SCORE,
    pr.RISK_SCORE_MODEL_NAME,
    pr.RISK_BAND,
    pr.HIGH_RISK_FLAG,
    dd.CALENDAR_DATE AS RISK_AS_OF_DATE,
    dd.YEAR_NUMBER AS RISK_YEAR,
    dd.MONTH_NUMBER AS RISK_MONTH,
    COUNT(DISTINCT e.ENCOUNTER_KEY) AS RECENT_ENCOUNTER_COUNT,
    SUM(CASE WHEN e.READMISSION_FLAG = TRUE THEN 1 ELSE 0 END) AS RECENT_READMISSION_COUNT,
    COUNT(DISTINCT fd.DIAGNOSIS_FACT_KEY) AS RECENT_DIAGNOSIS_COUNT,
    COUNT(DISTINCT fm.MEDICATION_ORDER_KEY) AS CURRENT_MEDICATION_COUNT,
    ROUND(AVG(e.LENGTH_OF_STAY_DAYS), 2) AS AVG_RECENT_LOS,
    ic.COVERAGE_TIER,
    pp.PAYER_NAME
FROM ANALYTICS.FACT_PATIENT_RISK pr
LEFT JOIN ANALYTICS.DIM_PATIENT p ON pr.PATIENT_KEY = p.PATIENT_KEY AND p.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_DATE dd ON pr.AS_OF_DATE_KEY = dd.DATE_KEY
LEFT JOIN ANALYTICS.FACT_ENCOUNTER e ON pr.PATIENT_KEY = e.PATIENT_KEY 
    AND e.ADMIT_DATE_KEY >= (pr.AS_OF_DATE_KEY - 18250)
    AND e.ADMIT_DATE_KEY <= pr.AS_OF_DATE_KEY
LEFT JOIN ANALYTICS.FACT_DIAGNOSIS fd ON e.ENCOUNTER_KEY = fd.ENCOUNTER_KEY
LEFT JOIN ANALYTICS.FACT_MEDICATION_ORDER fm ON e.ENCOUNTER_KEY = fm.ENCOUNTER_KEY
LEFT JOIN ANALYTICS.DIM_INSURANCE_COVERAGE ic ON e.INSURANCE_COVERAGE_KEY = ic.INSURANCE_COVERAGE_KEY 
    AND ic.IS_CURRENT = TRUE
LEFT JOIN ANALYTICS.DIM_PAYER_PLAN pp ON e.PAYER_PLAN_KEY = pp.PAYER_PLAN_KEY 
    AND pp.IS_CURRENT = TRUE
GROUP BY 
    p.PATIENT_KEY,
    p.PATIENT_ID,
    p.FIRST_NAME,
    p.LAST_NAME,
    p.DATE_OF_BIRTH,
    p.GENDER,
    pr.RISK_SCORE,
    pr.RISK_SCORE_MODEL_NAME,
    pr.RISK_BAND,
    pr.HIGH_RISK_FLAG,
    dd.CALENDAR_DATE,
    dd.YEAR_NUMBER,
    dd.MONTH_NUMBER,
    ic.COVERAGE_TIER,
    pp.PAYER_NAME;

